+     Rboolean inclose;                   /* TRUE if window is being closed */
  } x11Desc;


***************
*** 145,151 ****
  static Atom _XA_WM_PROTOCOLS, protocol;

  static Rboolean displayOpen = FALSE;
- static Rboolean inclose = FALSE;
